  if (!conDatos.length) continue;
  hayTablas = true;
  html += `<h2 style="font-size:14px;">🔹 ${esc(app)}</h2>`;
  for (const r of conDatos) {
    html += `<h3 style="font-size:14px;">Punto ${esc(r.queryId)}: ${esc(r.description)} <small>(${esc(r.country)}/${esc(r.target_env)})</small></h3>`;
    const data = r.result.slice(0, 150);
    const headers = Object.keys(data[0] || {}).slice(0, 10);
    html += `<table border="1" cellpadding="4" cellspacing="0" style="border-collapse:collapse;"><tr bgcolor="#f2f2f2">`;
    for (const h of headers) html += `<th align="left">${esc(h)}</th>`;
    html += `</tr>`;
    for (const row of data) { html += '<tr>'; for (const h of headers) html += `<td>${esc(row[h])}</td>`; html += '</tr>'; }
    html += `</table>`;
  }
}

if (!errores.length && !hayTablas) {
  if (['Hourly','Bi-hourly','Nightly'].includes(type)) return [];
  html += `<p>✅ Sin novedades.</p>`;
}
html += `</div>`;
return { json: { htmlContent: html } };
